double tim_sum;
typedef pair<long long, long long > P;
struct Edge {
    long long to;
    long long cost;
};
using Graph = vector<vector<Edge>>;
void dijkstra(const Graph& G, int s, vector<long long>& dis, vector<long long>& ans) {
    int N = G.size();
    dis.resize(N, inf);
    ans.resize(N, 0);
    priority_queue<P, vector<P>, greater<P>> pq;
    dis[s] = 0;
    ans[s] = 1;
    pq.emplace(dis[s], s);
    while (!pq.empty()) {
        P p = pq.top();
        pq.pop();
        int v = p.second;
        if (dis[v] < p.first) {
            continue;
        }
        for (auto& e : G[v]) {
            if (dis[e.to] > dis[v] + e.cost) {
                dis[e.to] = dis[v] + e.cost;
                ans[e.to] = ans[v];
                pq.emplace(dis[e.to], e.to);
            }
            else if (dis[e.to] == dis[v] + e.cost) {
                ans[e.to] += ans[v];
                ans[e.to] %= INF;
            }
        }
    }
}
