                DP[game.X[turn]][game.Y[turn]] = 0;
                pair<int, int>F;
                while (!que.empty()) {
                    int a = que.front().first, b = que.front().second;
                    if (game.C[a][b]) {
                        F = { a,b };
                        break;
                    }
                    for (int i = 0; i < 4; i++) {
                        Act act = { 0,i };
                        if (game.isOK(act)) {
